What will be the output of the following code that manually splits a string using loops?

```c
#include

int main() {
    char str[] = "Hi C";
    char word[10];
    int i = 0, j = 0;

    while (1) {
        if (str[i] == ' ' || str[i] == '\0') {
            word[j] = '\0';
            printf("%s\n", word);
            j = 0;
            if (str[i] == '\0') break;
        } else {
            word[j++] = str[i];
        }
        i++;
    }

    return 0;
}
```

